INSERT INTO public.reviews (user_id, api_item_id, type, content, created_at) VALUES
('5ec29e6d-74a5-46cf-9f30-4202701e7406', '1097861387', 'album', 'Asporto crur adversus depromo adhaero tumultus repellendus thymum occaecati. Alioqui et comedo debeo autem aggero viridis.', NOW() - interval '4 days'),
('abadf845-3b75-4de0-a843-20645bab26a4', '1097861387', 'album', 'Cerno verbera illo ademptio alveus suffragium atque. Cognatus reiciendis vulgivagus ratione cupressus.', NOW() - interval '51 days'),
('dd032b23-50dc-4749-ba76-bad50711b69f', '1097861387', 'album', 'Aequitas bardus comburo laborum doloribus. Caveo tersus demo complectus sit somniculosus audio sufficio synagoga. Blanditiis virtus alias defleo delibero crux quasi.', NOW() - interval '65 days'),
('afa8bb24-a872-4aca-8caf-facf1312c484', '1097861387', 'album', 'Labore tersus attonbitus commemoro dolor conturbo.', NOW() - interval '89 days'),
('2ff067ce-a906-4e20-bb85-c717f5c3987f', '1097861387', 'album', 'Cena aurum adduco vigor delego alioqui verbum suggero theologus auctor. Et verus celebrer basium aperio contra curvo clam curto. Caecus truculenter verumtamen ut virga beatae.', NOW() - interval '26 days'),
('72dacf62-c66b-4c8b-bdc8-299282376776', '1097861387', 'album', 'Quis versus bis doloremque infit iste. Capillus inventore aperio suadeo deficio. Succedo claustrum tribuo.', NOW() - interval '34 days'),
